function updateAttendanceSummary() {
    const classVal = document.getElementById('summary-class-select').value;
    const roomVal = document.getElementById('summary-room-select').value;

    let present = 0, late = 0, absent = 0, unchecked = 0;
    let total = 0;

    const history = getAttendanceHistory();
    const dateInput = document.querySelector('#panel-attendance #attendance-date-select');
    const targetDateStr = dateInput ? formatToThaiDate(dateInput.value) : getTodayThaiDate();

    // Check if there is saved history for this class and room on the active date
    const entry = history.find(h => h.date === targetDateStr && (h.class || 'm3') === classVal && (h.room || '1') === roomVal);

    if (entry) {
        present = entry.present;
        late = entry.late;
        absent = entry.absent;
        total = entry.total;
        unchecked = 0;
    } else {
        // No saved history, fallback to reading DOM if classVal and roomVal are currently selected
        const curClass = document.getElementById('class-select') ? document.getElementById('class-select').value : '';
        const curRoom = document.getElementById('room-select') ? document.getElementById('room-select').value : '';

        if (classVal === curClass && roomVal === curRoom) {
            const studentIds = ['stu-1', 'stu-2', 'stu-3'];
            studentIds.forEach(id => {
                const tabTable = document.getElementById('attendance-today-content');
                const actionCell = tabTable ? tabTable.querySelector('#action-' + id) : null;
                if (actionCell) {
                    const badge = actionCell.querySelector('.status-badge');
                    if (badge) {
                        if (badge.classList.contains('present')) present++;
                        else if (badge.classList.contains('late')) late++;
                        else if (badge.classList.contains('absent')) absent++;
                    } else {
                        unchecked++;
                    }
                }
            });
            total = studentIds.length;
        } else {
            // Fallback to deterministic mock statistics
            const baseSize = classVal === 'm1' ? 30 : classVal === 'm2' ? 28 : 25;
            const offset = parseInt(roomVal) * 2;
            total = baseSize - offset;

            present = Math.round(total * 0.88);
            late = Math.round(total * 0.08);
            absent = total - present - late;
            unchecked = 0;
        }
    }

